INSERT INTO excusals (employee_id, training_type_id, reason, source)
SELECT e.id, sr.training_type_id, sr.reason, 'access'
FROM source_rows sr
JOIN employees e ON lower(e.last_name) = lower(sr.last_name) AND lower(e.first_name) = lower(sr.first_name)
